import { RouteProp, useNavigation, useRoute } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useContext, useEffect, useMemo, useState } from 'react';
import {
  ActivityIndicator,
  Alert,
  Linking,
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  View
} from 'react-native';
import { AuthContext } from '../../App';
import OrderStatusTracker from '../components/OrderStatusTracker';
import {
  canCancelOrder,
  canModifyOrder,
  formatCurrency,
  formatOrderDate,
  formatOrderNumber,
  ORDER_STATUS_META
} from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { cancelOrder, getOrderById, OrderRecord, OrderStatus, updateOrderStatus } from '../services/firebaseService';

type RouteProps = RouteProp<RootStackParamList, 'OrderDetails'>;
type NavigationProp = NativeStackNavigationProp<RootStackParamList>;

const ownerFlow: OrderStatus[] = ['pending', 'confirmed', 'preparing', 'out_for_delivery', 'delivered'];

const nextStatusLabel: Record<OrderStatus, string> = {
  pending: 'Confirm Order',
  confirmed: 'Mark Preparing',
  preparing: 'Mark Out for Delivery',
  out_for_delivery: 'Mark Delivered',
  delivered: 'Delivered',
  cancelled: 'Cancelled'
};

const OrderDetailsScreen = () => {
  const route = useRoute<RouteProps>();
  const navigation = useNavigation<NavigationProp>();
  const { profile } = useContext(AuthContext);
  const [order, setOrder] = useState<OrderRecord | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    let active = true;
    const loadOrder = async () => {
      const data = await getOrderById(route.params.orderId);
      if (active) {
        setOrder(data);
        setLoading(false);
      }
    };
    loadOrder();
    return () => {
      active = false;
    };
  }, [route.params.orderId]);

  const nextStatus = useMemo(() => {
    if (!order) {
      return null;
    }
    const currentIndex = ownerFlow.indexOf(order.status);
    if (currentIndex === -1 || currentIndex === ownerFlow.length - 1) {
      return null;
    }
    return ownerFlow[currentIndex + 1];
  }, [order]);

  if (loading) {
    return (
      <SafeAreaView style={styles.loaderContainer}>
        <ActivityIndicator size="large" color="#0D8DD8" />
      </SafeAreaView>
    );
  }

  if (!order) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.emptyCard}>
          <Text style={styles.emptyTitle}>Order not found</Text>
          <Text style={styles.emptyText}>We could not load this order right now.</Text>
        </View>
      </SafeAreaView>
    );
  }

  const isOwner = profile?.role === 'owner';
  const statusMeta = ORDER_STATUS_META[order.status];

  const handleAdvanceStatus = async () => {
    if (!nextStatus) {
      return;
    }
    setSaving(true);
    try {
      await updateOrderStatus(order.id!, nextStatus);
      setOrder({ ...order, status: nextStatus });
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    Alert.alert('Cancel order', 'Are you sure you want to cancel this order?', [
      { text: 'No' },
      {
        text: 'Yes, cancel',
        style: 'destructive',
        onPress: async () => {
          await cancelOrder(order.id!);
          setOrder({ ...order, status: 'cancelled' });
        }
      }
    ]);
  };

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <View style={styles.heroCard}>
          <Text style={styles.heroLabel}>{isOwner ? 'Owner order view' : 'Order details'}</Text>
          <Text style={styles.heroTitle}>{formatOrderNumber(order)}</Text>
          <View style={[styles.statusPill, { backgroundColor: statusMeta.background }]}>
            <Text style={[styles.statusPillText, { color: statusMeta.text }]}>{statusMeta.label}</Text>
          </View>
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Delivery progress</Text>
          <OrderStatusTracker status={order.status} />
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Customer information</Text>
          <Text style={styles.itemLabel}>Name</Text>
          <Text style={styles.itemValue}>{order.customerName}</Text>
          <Text style={styles.itemLabel}>Phone</Text>
          <Text style={styles.itemValue}>{order.phone || 'Not available'}</Text>
          <Text style={styles.itemLabel}>Address</Text>
          <Text style={styles.itemValue}>{order.address || 'Not available'}</Text>
        </View>

        <View style={styles.sectionCard}>
          <Text style={styles.sectionTitle}>Order summary</Text>
          <View style={styles.summaryGrid}>
            <View style={styles.summaryBox}>
              <Text style={styles.summaryBoxLabel}>Order date</Text>
              <Text style={styles.summaryBoxValue}>{formatOrderDate(order.createdAt)}</Text>
            </View>
            <View style={styles.summaryBox}>
              <Text style={styles.summaryBoxLabel}>Quantity</Text>
              <Text style={styles.summaryBoxValue}>{order.quantity} cans</Text>
            </View>
            <View style={styles.summaryBox}>
              <Text style={styles.summaryBoxLabel}>Amount</Text>
              <Text style={styles.summaryBoxValue}>{formatCurrency(order.totalAmount)}</Text>
            </View>
            <View style={styles.summaryBox}>
              <Text style={styles.summaryBoxLabel}>Payment type</Text>
              <Text style={styles.summaryBoxValue}>{order.paymentMethod}</Text>
            </View>
          </View>
          <Text style={styles.itemLabel}>Delivery slot</Text>
          <Text style={styles.itemValue}>{order.deliverySlot}</Text>
          <Text style={styles.itemLabel}>Expected arrival</Text>
          <Text style={styles.itemValue}>{order.expectedDeliveryTime}</Text>
          {order.note ? (
            <>
              <Text style={styles.itemLabel}>Customer note</Text>
              <Text style={styles.itemValue}>{order.note}</Text>
            </>
          ) : null}
        </View>

        {isOwner ? (
          <View style={styles.sectionCard}>
            <Text style={styles.sectionTitle}>Owner actions</Text>
            <View style={styles.actionRow}>
              <Pressable style={styles.primaryButton} onPress={handleAdvanceStatus} disabled={!nextStatus || saving}>
                <Text style={styles.primaryButtonText}>
                  {saving ? 'Updating...' : nextStatus ? nextStatusLabel[order.status] : 'No more updates'}
                </Text>
              </Pressable>
              <Pressable style={styles.secondaryButton} onPress={() => Linking.openURL(`tel:${order.phone}`)}>
                <Text style={styles.secondaryButtonText}>Call Customer</Text>
              </Pressable>
            </View>
          </View>
        ) : (
          <View style={styles.sectionCard}>
            <Text style={styles.sectionTitle}>Customer actions</Text>
            <View style={styles.actionRow}>
              <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('OrderTracking', { orderId: order.id })}>
                <Text style={styles.primaryButtonText}>Track Order</Text>
              </Pressable>
              {canModifyOrder(order.status) ? (
                <Pressable style={styles.secondaryButton} onPress={() => navigation.navigate('NewOrder', { orderId: order.id })}>
                  <Text style={styles.secondaryButtonText}>Modify Order</Text>
                </Pressable>
              ) : null}
            </View>
            {canCancelOrder(order.status) ? (
              <Pressable style={styles.cancelButton} onPress={handleCancel}>
                <Text style={styles.cancelButtonText}>Cancel Order</Text>
              </Pressable>
            ) : null}
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#F2F9FF'
  },
  loaderContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#F2F9FF'
  },
  content: {
    padding: 18,
    paddingBottom: 30
  },
  heroCard: {
    backgroundColor: '#10324A',
    borderRadius: 28,
    padding: 20
  },
  heroLabel: {
    color: '#AEE6FF',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  heroTitle: {
    marginTop: 10,
    color: 'white',
    fontSize: 30,
    fontWeight: '900'
  },
  statusPill: {
    marginTop: 14,
    alignSelf: 'flex-start',
    borderRadius: 999,
    paddingHorizontal: 12,
    paddingVertical: 8
  },
  statusPillText: {
    fontSize: 12,
    fontWeight: '800'
  },
  sectionCard: {
    marginTop: 16,
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18
  },
  sectionTitle: {
    color: '#10324A',
    fontSize: 19,
    fontWeight: '800'
  },
  itemLabel: {
    marginTop: 14,
    color: '#6D8699',
    fontSize: 12,
    fontWeight: '700',
    textTransform: 'uppercase'
  },
  itemValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 15,
    fontWeight: '800',
    lineHeight: 22
  },
  summaryGrid: {
    marginTop: 14,
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 10
  },
  summaryBox: {
    width: '47%',
    borderRadius: 18,
    backgroundColor: '#F6FBFF',
    padding: 12
  },
  summaryBoxLabel: {
    color: '#6D8699',
    fontSize: 11,
    fontWeight: '700'
  },
  summaryBoxValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 14,
    fontWeight: '800'
  },
  actionRow: {
    marginTop: 14,
    gap: 10
  },
  primaryButton: {
    backgroundColor: '#0D8DD8',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: '900'
  },
  secondaryButton: {
    backgroundColor: '#EAF7FF',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
